"use strict";module.exports={meta:{type:"suggestion",docs:{description:"Enforce `default` clauses in `switch` statements to be last",recommended:!1,url:"https://eslint.org/docs/latest/rules/default-case-last"},schema:[],messages:{notLast:"Default clause should be the last clause."}},create:e=>({SwitchStatement(t){const s=t.cases,a=s.findIndex(e=>null===e.test);if(-1!==a&&a!==s.length-1){const t=s[a];e.report({node:t,messageId:"notLast"})}}})};